const msg = $input.first().json;
const body = msg.textPlain || msg.textHtml || msg.text || msg.snippet || '';
return [{
  json: {
    input_type: 'email',
    source: 'gmail',
    _trigger: 'gmail',
    _needs_webhook_response: false,
    raw_input: [
      'From: ' + (msg.from || ''),
      'Subject: ' + (msg.subject || ''),
      'Body:',
      body
    ].join('\n')
  }
}];

const payload = $input.first().json;
const body = payload.body || payload;

if (body.input_type === 'name_card') {
  return [{
    json: {
      ...body,
      source: body.source || 'card_scan',
      _trigger: 'webhook',
      _needs_webhook_response: true
    }
  }];
}

const rawInput = body.raw_input || [
  body.company ? 'Company: ' + body.company : null,
  body.address ? 'Property address: ' + body.address : null,
  body.city ? 'City: ' + body.city : null,
  body.state ? 'State: ' + body.state : null,
  body.email ? 'Email: ' + body.email : null,
  body.firstName || body.lastName ? 'Contact: ' + [body.firstName, body.lastName].filter(Boolean).join(' ') : null
].filter(Boolean).join('\n');

return [{
  json: {
    ...body,
    input_type: body.input_type || 'manual',
    source: body.source || 'manual',
    raw_input: rawInput,
    _trigger: 'webhook',
    _needs_webhook_response: true
  }
}];

const row = $input.first().json;
const firstName = row.firstName || row['First Name'] || row.firstname || '';
const lastName = row.lastName || row['Last Name'] || row.lastname || '';
const company = row.company || row['Company'] || row['Company Name'] || '';
const address = row.address || row['Property Address'] || row['Address'] || '';
const city = row.city || row['City'] || '';
const state = row.state || row['State'] || '';
const email = row.email || row['Email'] || row['Email Address'] || '';

return [{
  json: {
    firstName,
    lastName,
    company,
    address,
    city,
    state,
    email,
    input_type: 'sheet_submission',
    source: 'sheet',
    _trigger: 'google_sheets',
    _needs_webhook_response: false,
    raw_input: [
      company ? 'Company: ' + company : null,
      address ? 'Property address: ' + address : null,
      city ? 'City: ' + city : null,
      state ? 'State: ' + state : null,
      email ? 'Email: ' + email : null,
      firstName || lastName ? 'Contact: ' + [firstName, lastName].filter(Boolean).join(' ') : null
    ].filter(Boolean).join('\n')
  }
}];

