const source = $input.first().json;
const raw = source.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
const cleaned = raw.replace(/```json|```/gi, '').trim();
try {
  const parsed = JSON.parse(cleaned);
  return [{ json: { ...parsed, _source: source.source || 'name_card', _input_type: 'name_card' } }];
} catch(e) {
  return [{ json: { _parse_error: true, _raw: raw, _source: 'name_card', _input_type: 'name_card' } }];
}

const source = $input.first().json;
const raw = source.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
const cleaned = raw.replace(/```json|```/gi, '').trim();
try {
  const parsed = JSON.parse(cleaned);
  return [{ json: { ...parsed, _source: source.source || source.input_type || 'text', _input_type: source.input_type || 'text' } }];
} catch(e) {
  return [{ json: { _parse_error: true, _raw: raw, _source: 'text', _input_type: 'text' } }];
}

const lead = $input.first().json;
const isEmail = lead._source === 'gmail' || lead._input_type === 'email';
const shouldEnrich = isEmail
  ? lead.is_potential_customer !== false && !!(lead.email || lead.contact_name || lead.company_name)
  : !!(lead.company_name && lead.address);

const validationError = shouldEnrich
  ? null
  : isEmail
    ? (lead.qualification_reason || 'Inbound email does not appear to be a likely customer inquiry.')
    : 'Gemini could not extract company_name and/or address from the input. Please provide more detail.';

return [{
  json: {
    ...lead,
    _should_enrich: shouldEnrich,
    _validation_error: validationError
  }
}];

