// Pull results from all three parallel API calls
const lead    = $items('Validate required fields')[0].json;
const osmArr  = $items('Geocode — Nominatim')[0].json;
const osm     = Array.isArray(osmArr) ? (osmArr[0] || {}) : (osmArr || {});
const placesR = $items('Google Places')[0].json;
const place   = placesR.candidates?.[0] || {};
const corpR   = $items('OpenCorporates')[0].json;
const corp    = corpR.results?.companies?.[0]?.company || {};

// ── Scoring weights (must sum to 1.0) ──────────────────────────────────
const W = {
  google_rating:    0.25,   // how well-regarded the property is
  review_volume:    0.20,   // proxy for active leasing activity
  address_verified: 0.20,   // data quality signal
  contact_quality:  0.20,   // can we actually reach this person?
  company_maturity: 0.15    // established operator = better buyer
};

function scale(val, max) {
  return Math.min(5, Math.round((val / max) * 5));
}

const currentYear = new Date().getFullYear();
const incYear = corp.incorporation_date
  ? parseInt(corp.incorporation_date.split('-')[0])
  : null;

const F = {
  google_rating:    place.rating ? Math.round(place.rating) : 0,
  review_volume:    scale(place.user_ratings_total || 0, 200),
  address_verified: osm.lat ? 5 : 0,
  contact_quality:  (lead.email && lead.phone) ? 5 : lead.email ? 3 : 1,
  company_maturity: incYear ? scale(currentYear - incYear, 10) : 2
};

const total = parseFloat(
  Object.keys(W).reduce((s, k) => s + W[k] * F[k], 0).toFixed(2)
);

// ── Insight strings shown to the rep ──────────────────────────────────
const insights = [];
if (!place.rating)
  insights.push('No Google listing found — low digital presence, worth verifying');
if (place.rating && place.rating >= 4.2)
  insights.push('Strong Google rating (' + place.rating + ') — likely stable, well-run operator');
if (place.rating && place.rating < 3.5)
  insights.push('Low Google rating (' + place.rating + ') — may have tenant issues; qualify carefully');
if ((place.user_ratings_total || 0) >= 100)
  insights.push('High review volume (' + place.user_ratings_total + ') — active leasing property');
if (!osm.lat)
  insights.push('Address could not be verified on OpenStreetMap — confirm with rep before outreach');
if (lead.unit_count && parseInt(lead.unit_count) >= 50)
  insights.push('Portfolio of ' + lead.unit_count + ' units — strong automation ROI case');
if (lead.notes)
  insights.push('Rep note: ' + lead.notes);
if (corp.company_number)
  insights.push('Registered company found: ' + (corp.name || lead.company_name) + (incYear ? ' (est. ' + incYear + ')' : ''));

// ── Priority tier ─────────────────────────────────────────────────────
const tier = total >= 4 ? 'hot' : total >= 2.5 ? 'warm' : 'cold';

return [{ json: {
  lead_id:      'lead_' + Math.random().toString(36).substr(2, 8),
  status:       'enriched',
  processed_at: new Date().toISOString(),
  input_type:   lead._input_type || 'unknown',
  source:       lead._source    || 'unknown',

  company_name: lead.company_name,
  address:      lead.address,
  city:         lead.city   || osm.address?.city   || null,
  state:        lead.state  || osm.address?.state  || null,
  zip:          lead.zip    || osm.address?.postcode || null,

  contact: {
    name:      lead.contact_name || null,
    email:     lead.email        || null,
    phone:     lead.phone        || null,
    job_title: lead.job_title    || null
  },

  unit_count: lead.unit_count || null,
  notes:      lead.notes      || null,

  enrichment: {
    google_name:     place.name             || null,
    google_rating:   place.rating           || null,
    review_count:    place.user_ratings_total || null,
    place_id:        place.place_id         || null,
    address_verified: !!osm.lat,
    lat:             osm.lat  || null,
    lon:             osm.lon  || null,
    corp_name:       corp.name              || null,
    corp_number:     corp.company_number    || null,
    incorporated:    incYear                || null
  },

  score: {
    total:    total,
    tier:     tier,
    factors:  F,
    weights:  W,
    insights: insights
  }
}}];
